import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to start/deal the blackjack round.
 * If you later need to target a specific table, add a tableId param.
 */
export class BlackjackDealComposer implements IMessageComposer<Array<number>> {
    private _data: number[];

    // Optional: pass a tableId if you support multiple tables. Default 0.
    constructor(tableId: number = 0) {
        this._data = [tableId];
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        // no-op
    }
}
